import SwiftUI

struct SettingsView: View { @State private var availability = RecipeModelAvailability.temporarilyUnavailable; private let checker = AppleSystemModelAvailabilityChecker(); var body: some View { NavigationStack { List { Section("Apple Intelligence") { ModelAvailabilityBanner(availability: availability); Button("Verifica stato modello") { Task { availability = await checker.availability() } } } Section("Privacy") { Text("DishD è local-first: ricette, ingredienti e importazioni restano sul dispositivo. Non sono configurati backend, analytics di terze parti o modelli AI cloud.") } Section("Informazioni") { Text("Nome prodotto: \(AppBrand.productName)"); Text("Lingua interfaccia: italiano") } }.navigationTitle("Impostazioni").task { availability = await checker.availability() } } } }
struct ModelAvailabilityBanner: View { let availability: RecipeModelAvailability; var body: some View { Label(availability.italianMessage, systemImage: availability == .available ? "checkmark.circle" : "exclamationmark.triangle").foregroundStyle(availability == .available ? .green : .orange) } }
